// src/api/auth.js
import axios from "axios";

const API_URL = "https://prasa-app-yde3.onrender.com/api/app";


export const loginUser = (empId, password) => {
  return axios.post(API, { action: "login", empId, password });
};

export const getDashboard = (empId) => {
  return axios.post(API, { action: "dashboard", empId });
};

export const addTravel = (payload) => {
  return axios.post(API, { action: "addTravel", ...payload });
};

export const addTicket = (payload) => {
  return axios.post(API, { action: "addTicket", ...payload });
};

export const getHistory = (empId) => {
  return axios.post(API, { action: "getHistory", empId });
};

export const getGraphData = (empId) => {
  return axios.post(API, { action: "getGraphData", empId });
};

export const uploadBill = (payload) => {
  return axios.post(API, { action: "uploadBill", ...payload });
};

export const generateReport = (payload) => {
  return axios.post(API, { action: "generateReport", ...payload });
};
